    "bindings": [
      {
        "name": "SYNCED_STATE",
        "class_name": "SyncedStateServer"
      }
    ]
  },

  // Migrations for Durable Objects with SQLite storage
  "migrations": [
    {
      "tag": "v1",
      "new_sqlite_classes": ["SyncedStateServer"]
    }
  ],

  // Environment variables
  "vars": {
    // Add your environment variables here
  }
}

